import * as React from 'react';

// Ref: https://giters.com/mikecao/umami/issues/693#issuecomment-856916946
import { extent } from 'd3-array';

import { AxisBottom, AxisLeft } from '@visx/axis';
import { Group } from '@visx/group';
import ParentSize from '@visx/responsive/lib/components/ParentSize';
import { scaleLinear } from '@visx/scale';

import { useBlogPostContext } from '../../../components/BlogPostContext';

type Item = {
  body_mass_g: number;
  culmen_depth_mm: number;
  culmen_length_mm: number;
  flipper_length_mm: number;
  island: string;
  sex: string;
  species: string;
};

export type Props = {
  width: number;
  height: number;
  data: Item[];
};

const Content = React.memo((props: Props) => {
  const { width, height, data } = props;
  const xScale = scaleLinear({
    domain: extent(data.map(({ flipper_length_mm }) => flipper_length_mm)) as [
      number,
      number
    ],
    range: [0, width],
    nice: true,
  });
  const yScale = scaleLinear({
    domain: extent(data.map(({ body_mass_g }) => body_mass_g)) as [
      number,
      number
    ],
    range: [height, 0],
    nice: true,
  });
  // console.log('Content', { width, height });
  return (
    <>
      <svg width={width} height={height}>
        <g />
        <AxisLeft scale={yScale} />
        <AxisBottom scale={xScale} top={height} />
        <Group>
          {data
            .filter(({ body_mass_g }) => body_mass_g)
            .map(({ flipper_length_mm, body_mass_g }, i) => (
              <circle
                key={`${i}`}
                cx={xScale(flipper_length_mm)}
                cy={yScale(body_mass_g)}
                r={4}
              />
            ))}
        </Group>
      </svg>
    </>
  );
});

const ScatterChart = React.memo(() => {
  const { data } = useBlogPostContext();
  return (
    <ParentSize>
      {({ width }) => <Content width={width} height={300} data={data} />}
    </ParentSize>
  );
});

export default ScatterChart;
